//Navega Tabela Imposto For Each Order EmpCod,ImpLctCod,ImpFilCod,ImpUfeCod,ImpGruImpCod,ImpCatCod
If EmpCod <> &EmpCod or ImpFilCod <> &ImpFilCod &EmpCod = EmpCod &ImpFilCod = ImpFilCod RetornaRegimeTributarioFilial.Call(EmpCod, ImpFilCod, &FilRegTrib, &CImpOriUfeCod) EndIf
&sdtCadastroTabelaImpostoCbs = new()
&sdtCadastroTabelaImpostoCbs.EmpCod = EmpCod &sdtCadastroTabelaImpostoCbs.CImpTbFilCod = ImpFilCod &sdtCadastroTabelaImpostoCbs.CImpLctCod = ImpLctCod &sdtCadastroTabelaImpostoCbs.CImpOriUfeCod = &CImpOriUfeCod //UF ORIGEM &sdtCadastroTabelaImpostoCbs.CImpDstUfeCod = ImpUfeCod &sdtCadastroTabelaImpostoCbs.CImpGruImpCod = ImpGruImpCod &sdtCadastroTabelaImpostoCbs.CImpCatCod = ImpCatCod &sdtCadastroTabelaImpostoCbs.CImpDtaIni = YmDtoD(2025, 10, 1)
&sdtCadastroTabelaImpostoCbs.CImpCfoCod = ImpCfoCod
if SitCod < 100 &Varchar = padL(trim(str(SitCod)), 2, '0') Else &Varchar = trim(str(SitCod)) Endif &sdtCadastroTabelaImpostoCbs.CImpCstCod.FromString(&Varchar)
&sdtCadastroTabelaImpostoCbs.CImpObsInf = ImpObsInf &sdtCadastroTabelaImpostoCbs.CImpDtaAlt = serverNow()
&sdtCadastroTabelaImpostoCbs.CImpAlqMVA = ImpAlqMVA &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt = ImpAlqIcmInt &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmInt = ImpRedAlqIcmInt &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt = ImpAlqIcmExt &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmExt = ImpRedAlqIcmExt &sdtCadastroTabelaImpostoCbs.CImpDif = ImpDif &sdtCadastroTabelaImpostoCbs.CImpCBenef = ImpCBenef &sdtCadastroTabelaImpostoCbs.CImpAlqIcmUFDest = ImpALqIcmUFDest &sdtCadastroTabelaImpostoCbs.CImpIcmsMotDes = ImpIcmsMotDes &sdtCadastroTabelaImpostoCbs.CImpTaxFecop = ImpTaxFecop &sdtCadastroTabelaImpostoCbs.CImpIcmsRet = ImpIcmsRet &sdtCadastroTabelaImpostoCbs.CImpAlqIcmStUF = ImpAlqIcmStUF
//INCLUIR E EXCLUIR &sdtCadastroTabelaImpostoCbs.CImpIncIPI = ImpIncIpi &sdtCadastroTabelaImpostoCbs.CImpExcPisCofins = ImpExcPisCofins
//IPI &sdtCadastroTabelaImpostoCbs.CImpCstIpi = ImpCstIpi &sdtCadastroTabelaImpostoCbs.CImpIpi = ImpIPI &sdtCadastroTabelaImpostoCbs.CImpIpiEnq = ImpIpiEnq
//INSS &sdtCadastroTabelaImpostoCbs.CImpAlqInss = ImpAlqInss
//PIS e COFINS &sdtCadastroTabelaImpostoCbs.CImpCstPisCofins.FromString(ImpCstPis.ToString()) &sdtCadastroTabelaImpostoCbs.CImpCofins = ImpCofins &sdtCadastroTabelaImpostoCbs.CImpCofinsRed = ImpCofinsRed &sdtCadastroTabelaImpostoCbs.CImpPis = ImpPis &sdtCadastroTabelaImpostoCbs.CImpPisRed = ImpPisRed
//IBS CBS // &sdtCadastroTabelaImpostoCbs.CltSitCod = '000' //Tributado integrailmente // &sdtCadastroTabelaImpostoCbs.CltClsTrib = '000001'
// &sdtCadastroTabelaImpostoCbs.CImpIbsUfPer = 0.9 // &sdtCadastroTabelaImpostoCbs.CImpIbsUfRed = 0 // &sdtCadastroTabelaImpostoCbs.CImpIbsMunPer = 0 // &sdtCadastroTabelaImpostoCbs.CImpIbsMunRed = 0 // &sdtCadastroTabelaImpostoCbs.CImpIbsUnPer = 0.1 // &sdtCadastroTabelaImpostoCbs.CImpIbsUnRed = 0
//OBSERVACOES &sdtObservacaoNota.Clear() For Each Order EmpCod,ImpLctCod,ImpFilCod,ImpUfeCod,ImpGruImpCod,ImpCatCod, ObsCod &sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = ObsCod &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) EndFor
//GRAVA NOVA TABELA IMPOSTO prcGravaNovaConfiguracaoImposto.Call('ADD', &sdtCadastroTabelaImpostoCbs, &sdtObservacaoNota)
EndFor
